arguments.new_str:
class EnvVarCheck
{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9 breaking change: empty env vars are no longer treated as unset.
        // Previously GetEnvironmentVariable returned null for both unset and empty;
        // now it returns "" for empty, so we must distinguish the two cases.
        var val = Environment.GetEnvironmentVariable("MY_FLAG");
        if (val is null)
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
        else if (val.Length == 0)
        {
            Console.WriteLine("MY_FLAG explicitly empty");
        }
    }
}

